import React from 'react';
import { useLanguage } from '../contexts/LanguageContext';
import { getKeyboardConfig } from '../config/keyboardLoader';
import './VirtualKeyboard.css';

const VirtualKeyboard = ({ activeKey, isCorrect, targetKeys = [] }) => {
  const { language } = useLanguage();
  const { layout, fingerMap, fingerNames } = getKeyboardConfig(language);

  if (!layout || layout.length === 0) return null;

  const getKeyClass = (key) => {
    const classes = ['key'];

    // Finger color class
    const finger = fingerMap?.[key];
    if (finger) classes.push(finger);

    // Target key highlight (keys being taught in this lesson)
    if (targetKeys.includes(key)) classes.push('target-key');

    // Active key (currently expected character)
    if (activeKey && key === activeKey) {
      classes.push('active-key');
      if (isCorrect === true)  classes.push('key-correct');
      if (isCorrect === false) classes.push('key-incorrect');
    }

    // Wide keys
    if (key === 'Backspace') classes.push('key-backspace');
    if (key === 'Tab')       classes.push('key-tab');
    if (key === 'CapsLock')  classes.push('key-capslock');
    if (key === 'Enter')     classes.push('key-enter');
    if (key === 'Shift' || key === 'ShiftR') classes.push('key-shift');
    if (key === ' ')         classes.push('key-space');

    return classes.join(' ');
  };

  const getDisplayLabel = (key) => {
    if (key === ' ')        return '___';
    if (key === 'Backspace') return '⌫';
    if (key === 'Tab')      return 'Tab';
    if (key === 'CapsLock') return 'Caps';
    if (key === 'Enter')    return '↵';
    if (key === 'Shift' || key === 'ShiftR') return '⇧';
    return key;
  };

  return (
    <div className="virtual-keyboard">
      {/* Finger name legend */}
      {fingerNames && (
        <div className="finger-legend">
          {Object.entries(fingerNames).map(([finger, name]) => (
            <span key={finger} className={`finger-label ${finger}`}>{name}</span>
          ))}
        </div>
      )}

      {/* Keyboard rows */}
      <div className="keyboard-rows">
        {layout.map((row, rowIndex) => (
          <div key={rowIndex} className={`keyboard-row row-${rowIndex}`}>
            {row.map((key, keyIndex) => (
              <div
                key={`${rowIndex}-${keyIndex}-${key}`}
                className={getKeyClass(key)}
                title={fingerMap?.[key] ? (fingerNames?.[fingerMap[key]] || fingerMap[key]) : ''}
              >
                <span className="key-label">{getDisplayLabel(key)}</span>
              </div>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
};

export default VirtualKeyboard;
